import { useState, useEffect, useRef } from "react";
import { auth, db, realtimeDb } from "../../firebase/firebaseConfig";
import { doc, onSnapshot } from "firebase/firestore";
import { ref, push, onValue } from "firebase/database";
import { signOut } from "firebase/auth";
import { useNavigate } from "react-router-dom";

const CustomerChat = () => {
  const [customerData, setCustomerData] = useState(null);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const messagesEndRef = useRef(null);
  const navigate = useNavigate();
  const user = auth.currentUser;

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  useEffect(() => {
    if (!user) { navigate("/"); return; }
    const unsub = onSnapshot(doc(db, "users", user.uid), (snap) => {
      if (snap.exists()) setCustomerData({ id: user.uid, ...snap.data() });
    });
    return () => unsub();
  }, []);

  useEffect(() => {
    if (!user) return;
    const chatRef = ref(realtimeDb, `chats/${user.uid}`);
    const unsub = onValue(chatRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const msgs = Object.entries(data).map(([key, val]) => ({ id: key, ...val }));
        msgs.sort((a, b) => (a.timestamp || 0) - (b.timestamp || 0));
        setMessages(msgs);
      } else {
        setMessages([]);
      }
    });
    return () => unsub();
  }, []);

  const handleSend = async () => {
    if (!input.trim()) return;
    const chatRef = ref(realtimeDb, `chats/${user.uid}`);
    await push(chatRef, {
      text: input.trim(),
      sender: "customer",
      senderName: customerData?.name || "Customer",
      timestamp: Date.now(),
    });
    setInput("");
  };

  const handleKeyDown = (e) => {
    if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); handleSend(); }
  };

  const handleLogout = async () => {
    await signOut(auth);
    navigate("/");
  };

  const formatTime = (timestamp) => {
    if (!timestamp) return "";
    return new Date(timestamp).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
  };

  const getPriorityStyle = (priority) => {
    if (priority === "High") return { badge: "priority-high", emoji: "🔴" };
    if (priority === "Medium") return { badge: "priority-medium", emoji: "🟡" };
    return { badge: "priority-low", emoji: "🟢" };
  };

  return (
    <>
      <div className="bg-mesh" />
      <div style={{ position: "relative", zIndex: 1, height: "100vh", display: "flex", flexDirection: "column" }}>

        {/* Navbar */}
        <nav style={{
          display: "flex", alignItems: "center", justifyContent: "space-between",
          padding: "1rem 1.5rem",
          background: "rgba(15,23,42,0.9)",
          borderBottom: "1px solid var(--border)",
          backdropFilter: "blur(20px)", flexShrink: 0,
        }}>
          <div style={{ display: "flex", alignItems: "center", gap: "0.75rem" }}>
            <div style={{
              width: "36px", height: "36px",
              background: "linear-gradient(135deg, var(--accent), var(--accent2))",
              borderRadius: "10px", display: "flex", alignItems: "center",
              justifyContent: "center", fontSize: "1.1rem",
            }}>💬</div>
            <div>
              <p style={{ fontFamily: "'Syne', sans-serif", fontWeight: 700, fontSize: "0.95rem" }}>Support Chat</p>
              {customerData?.assignedAgent ? (
                <p style={{ fontSize: "0.7rem", color: "var(--success)" }}>● Connected with {customerData.assignedAgentName}</p>
              ) : (
                <p style={{ fontSize: "0.7rem", color: "var(--warning)" }}>⏳ Waiting for an agent...</p>
              )}
            </div>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: "0.75rem" }}>
            {customerData?.priority && (
              <span className={`role-badge ${getPriorityStyle(customerData.priority).badge}`} style={{ fontSize: "0.7rem" }}>
                {getPriorityStyle(customerData.priority).emoji} {customerData.priority} Priority
              </span>
            )}
            <button onClick={handleLogout} style={{
              padding: "0.4rem 0.9rem", borderRadius: "8px",
              border: "1px solid var(--border)", background: "transparent",
              color: "var(--text-muted)", cursor: "pointer", fontSize: "0.8rem",
              fontFamily: "'DM Sans', sans-serif",
            }}>Sign Out</button>
          </div>
        </nav>

        {/* Waiting Banner */}
        {!customerData?.assignedAgent && (
          <div style={{
            background: "rgba(251,191,36,0.08)",
            borderBottom: "1px solid rgba(251,191,36,0.2)",
            padding: "0.75rem 1.5rem",
            display: "flex", alignItems: "center", gap: "0.75rem", flexShrink: 0,
          }}>
            <div style={{ width: "8px", height: "8px", borderRadius: "50%", background: "var(--warning)" }} />
            <p style={{ fontSize: "0.85rem", color: "var(--warning)" }}>
              You are in the queue. An agent will join shortly.
            </p>
          </div>
        )}

        {/* Messages */}
        <div style={{ flex: 1, overflowY: "auto", padding: "1.5rem", display: "flex", flexDirection: "column", gap: "0.75rem" }}>
          <div style={{ textAlign: "center", marginBottom: "1rem" }}>
            <span style={{
              fontSize: "0.75rem", color: "var(--text-muted)",
              background: "rgba(148,163,184,0.08)",
              padding: "0.3rem 0.9rem", borderRadius: "20px",
              border: "1px solid var(--border)",
            }}>
              Chat started • {customerData?.priority} Priority
            </span>
          </div>

          {messages.length === 0 && (
            <div style={{ textAlign: "center", marginTop: "3rem", color: "var(--text-muted)" }}>
              <p style={{ fontSize: "2rem", marginBottom: "0.75rem" }}>👋</p>
              <p>Say hello! Your agent will respond shortly.</p>
            </div>
          )}

          {messages.map((msg) => {
            const isCustomer = msg.sender === "customer";
            return (
              <div key={msg.id} style={{ display: "flex", justifyContent: isCustomer ? "flex-end" : "flex-start" }}>
                <div style={{ maxWidth: "70%" }}>
                  {!isCustomer && (
                    <p style={{ fontSize: "0.72rem", color: "var(--text-muted)", marginBottom: "0.3rem", paddingLeft: "0.5rem" }}>
                      🎧 {msg.senderName}
                    </p>
                  )}
                  <div style={{
                    padding: "0.75rem 1rem",
                    borderRadius: isCustomer ? "18px 18px 4px 18px" : "18px 18px 18px 4px",
                    background: isCustomer ? "linear-gradient(135deg, var(--accent), var(--accent2))" : "rgba(30,41,59,0.9)",
                    border: isCustomer ? "none" : "1px solid var(--border)",
                    color: isCustomer ? "var(--primary)" : "var(--text)",
                    fontSize: "0.9rem", lineHeight: "1.5",
                  }}>
                    {msg.text}
                  </div>
                  <p style={{
                    fontSize: "0.68rem", color: "var(--text-muted)", marginTop: "0.25rem",
                    textAlign: isCustomer ? "right" : "left",
                  }}>
                    {formatTime(msg.timestamp)}
                  </p>
                </div>
              </div>
            );
          })}
          <div ref={messagesEndRef} />
        </div>

        {/* Input */}
        <div style={{
          padding: "1rem 1.5rem",
          background: "rgba(15,23,42,0.9)",
          borderTop: "1px solid var(--border)",
          backdropFilter: "blur(20px)", flexShrink: 0,
        }}>
          <div style={{ display: "flex", gap: "0.75rem", alignItems: "flex-end" }}>
            <textarea
              value={input} onChange={(e) => setInput(e.target.value)} onKeyDown={handleKeyDown}
              placeholder="Type your message... (Enter to send)"
              rows={1}
              style={{
                flex: 1, background: "rgba(30,41,59,0.8)",
                border: "1px solid var(--border)", borderRadius: "14px",
                padding: "0.8rem 1rem", color: "var(--text)",
                fontFamily: "'DM Sans', sans-serif", fontSize: "0.9rem",
                outline: "none", resize: "none", maxHeight: "120px", lineHeight: "1.5",
              }}
              onFocus={e => e.target.style.borderColor = "var(--accent)"}
              onBlur={e => e.target.style.borderColor = "var(--border)"}
            />
            <button
              onClick={handleSend} disabled={!input.trim()}
              style={{
                width: "46px", height: "46px", borderRadius: "12px", border: "none",
                background: input.trim() ? "linear-gradient(135deg, var(--accent), var(--accent2))" : "var(--border)",
                color: input.trim() ? "var(--primary)" : "var(--text-muted)",
                cursor: input.trim() ? "pointer" : "not-allowed",
                fontSize: "1.2rem", display: "flex", alignItems: "center", justifyContent: "center",
                flexShrink: 0, transition: "all 0.2s",
              }}
            >➤</button>
          </div>
          <p style={{ fontSize: "0.7rem", color: "var(--text-muted)", marginTop: "0.5rem", textAlign: "center" }}>
            Press Enter to send • Shift+Enter for new line
          </p>
        </div>
      </div>
    </>
  );
};

export default CustomerChat;
